-- 2. Split the single global 'custom-schools' overlay into per-school rows, then
--    drop the global row so it can no longer be read across schools.
do $mig$
declare g jsonb; sid text; v jsonb;
begin
  select value into g from public.kv_store where school_id='global' and key='custom-schools';
  if g is not null then
    for sid, v in select * from jsonb_each(g) loop
      insert into public.kv_store(school_id,key,value) values (sid,'custom-schools',v)
        on conflict (school_id,key) do update set value = excluded.value, updated_at = now();
    end loop;
    delete from public.kv_store where school_id='global' and key='custom-schools';
  end if;
end
$mig$;

commit;
